import java.util.ArrayList;
import java.util.List;

public class MarketingCampaignScheduler {

    public static class Campaign {
        String name;
        int cost;
        int expectedReturn;

        public Campaign(String name, int cost, int expectedReturn) {
            this.name = name;
            this.cost = cost;
            this.expectedReturn = expectedReturn;
        }
    }

    public static List<Campaign> selectCampaigns(List<Campaign> campaigns, int budget) {
        int n = campaigns.size();
        int[][] dp = new int[n + 1][budget + 1];

        for (int i = 1; i <= n; i++) {
            Campaign currentCampaign = campaigns.get(i - 1);
            for (int w = 0; w <= budget; w++) {
                if (currentCampaign.cost <= w) {
                    dp[i][w] = Math.max(
                            dp[i - 1][w],
                            dp[i - 1][w - currentCampaign.cost] + currentCampaign.expectedReturn
                    );
                } else {
                    dp[i][w] = dp[i - 1][w];
                }
            }
        }

        List<Campaign> selectedCampaigns = new ArrayList<>();
        int remainingBudget = budget;
        for (int i = n; i > 0 && remainingBudget > 0; i--) {
            if (dp[i][remainingBudget] != dp[i - 1][remainingBudget]) {
                Campaign selectedCampaign = campaigns.get(i - 1);
                selectedCampaigns.add(selectedCampaign);
                remainingBudget -= selectedCampaign.cost;
            }
        }

        return selectedCampaigns;
    }

    public static void main(String[] args) {
        List<Campaign> campaigns = new ArrayList<>();
        campaigns.add(new Campaign("Facebook", 200, 500));
        campaigns.add(new Campaign("Google", 300, 600));
        campaigns.add(new Campaign("Instagram", 100, 300));
        campaigns.add(new Campaign("Twitter", 150, 350));

        int budget = 500;
        List<Campaign> selectedCampaigns = selectCampaigns(campaigns, budget);

        System.out.println("Selected Campaigns:");
        int totalCost = 0;
        int totalReturn = 0;
        for (Campaign campaign : selectedCampaigns) {
            System.out.println(campaign.name + " - Cost: " + campaign.cost + ", Return: " + campaign.expectedReturn);
            totalCost += campaign.cost;
            totalReturn += campaign.expectedReturn;
        }
        System.out.println("Total Cost: " + totalCost);
        System.out.println("Total Expected Return: " + totalReturn);
    }
}
