import heapq
import os
from collections import defaultdict

class HuffmanNode:
    def __init__(self, char=None, freq=0, left=None, right=None):
        self.char = char
        self.freq = freq
        self.left = left
        self.right = right

    def __lt__(self, other):
        return self.freq < other.freq

def build_frequency_dict(data):
    frequency = defaultdict(int)
    for char in data:
        frequency[char] += 1
    return frequency

def build_huffman_tree(frequency):
    heap = []
    for char, freq in frequency.items():
        heapq.heappush(heap, HuffmanNode(char=char, freq=freq))

    while len(heap) > 1:
        left = heapq.heappop(heap)
        right = heapq.heappop(heap)
        merged = HuffmanNode(freq=left.freq + right.freq, left=left, right=right)
        heapq.heappush(heap, merged)

    return heapq.heappop(heap)

def build_codes(node, current_code="", codes=None):
    if codes is None:
        codes = {}
    if node.char is not None:
        codes[node.char] = current_code
    else:
        build_codes(node.left, current_code + "0", codes)
        build_codes(node.right, current_code + "1", codes)
    return codes

def encode_text(text, codes):
    encoded = ""
    for char in text:
        encoded += codes[char]
    return encoded

def huffman_compress(input_data, is_file=False):
    if is_file:
        with open(input_data, 'r') as file:
            text = file.read()
    else:
        text = input_data

    frequency = build_frequency_dict(text)
    huffman_tree = build_huffman_tree(frequency)
    codes = build_codes(huffman_tree)
    encoded_text = encode_text(text, codes)
    return encoded_text, codes

# Example usage:
# For a string:
# compressed_data, codebook = huffman_compress("example text", is_file=False)
# For a file:
# compressed_data, codebook = huffman_compress("input.txt", is_file=True)
