function findMaxProductivityPeriod(log) {
    if (log.length === 0) return { start: -1, end: -1, total: 0 };

    let maxTotal = log[0];
    let currentTotal = log[0];
    let start = 0;
    let tempStart = 0;
    let end = 0;

    for (let i = 1; i < log.length; i++) {
        if (currentTotal + log[i] > log[i]) {
            currentTotal += log[i];
        } else {
            currentTotal = log[i];
            tempStart = i;
        }

        if (currentTotal > maxTotal) {
            maxTotal = currentTotal;
            start = tempStart;
            end = i;
        }
    }

    return { start, end, total: maxTotal };
}
