#include <iostream>
#include <vector>
#include <unordered_map>
#include <climits>
#include <algorithm>

using namespace std;

struct Location {
    int id;
    int garbage;
    int distance;
};

unordered_map<string, int> memo;

int dp(int currentPos, int remainingCapacity, const vector<Location>& locations, vector<bool>& visited) {
    string key = to_string(currentPos) + "," + to_string(remainingCapacity);
    if (memo.find(key) != memo.end()) {
        return memo[key];
    }

    bool allVisited = true;
    for (bool v : visited) {
        if (!v) {
            allVisited = false;
            break;
        }
    }
    if (allVisited) {
        return locations[currentPos].distance; // Return to depot
    }

    int minCost = INT_MAX;
    for (int i = 0; i < locations.size(); ++i) {
        if (!visited[i] && locations[i].garbage <= remainingCapacity) {
            visited[i] = true;
            int cost = locations[currentPos].distance + dp(i, remainingCapacity - locations[i].garbage, locations, visited);
            minCost = min(minCost, cost);
            visited[i] = false;
        }
    }

    // Consider returning to depot if no more locations can be served with remaining capacity
    if (minCost == INT_MAX) {
        int returnCost = locations[currentPos].distance + dp(0, locations[0].garbage, locations, visited);
        minCost = returnCost;
    }

    memo[key] = minCost;
    return minCost;
}

int optimizeRoute(const vector<Location>& locations, int truckCapacity) {
    vector<bool> visited(locations.size(), false);
    visited[0] = true; // Depot is always visited first
    return dp(0, truckCapacity, locations, visited);
}

int main() {
    vector<Location> locations = {
        {0, 0, 0}, // Depot
        {1, 2, 5},
        {2, 3, 10},
        {3, 1, 7}
    };
    int truckCapacity = 4;

    int minFuel = optimizeRoute(locations, truckCapacity);
    cout << "Minimum fuel consumption: " << minFuel << endl;

    return 0;
}
