import java.util.ArrayList;
import java.util.List;

public class TextAlignment {
    public static List<String> justifyText(String[] words, int maxWidth) {
        int n = words.length;
        int[][] cost = new int[n][n];

        // Calculate cost matrix
        for (int i = 0; i < n; i++) {
            cost[i][i] = maxWidth - words[i].length();
            for (int j = i + 1; j < n; j++) {
                cost[i][j] = cost[i][j - 1] - words[j].length() - 1;
            }
        }

        // Adjust cost: negative cost means words don't fit
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                if (cost[i][j] < 0) {
                    cost[i][j] = Integer.MAX_VALUE;
                } else {
                    cost[i][j] = (int) Math.pow(cost[i][j], 2);
                }
            }
        }

        // DP to find minimal cost
        int[] minCost = new int[n];
        int[] result = new int[n];

        for (int i = n - 1; i >= 0; i--) {
            minCost[i] = cost[i][n - 1];
            result[i] = n;
            for (int j = n - 1; j > i; j--) {
                if (cost[i][j - 1] == Integer.MAX_VALUE) {
                    continue;
                }
                if (minCost[i] > minCost[j] + cost[i][j - 1]) {
                    minCost[i] = minCost[j] + cost[i][j - 1];
                    result[i] = j;
                }
            }
        }

        // Build the justified lines
        List<String> lines = new ArrayList<>();
        int i = 0;
        while (i < n) {
            int j = result[i];
            StringBuilder line = new StringBuilder();
            for (int k = i; k < j; k++) {
                line.append(words[k]);
                if (k != j - 1) {
                    line.append(" ");
                }
            }
            lines.add(line.toString());
            i = j;
        }

        return lines;
    }

    public static void main(String[] args) {
        String[] words = {"This", "is", "an", "example", "of", "text", "justification."};
        int maxWidth = 16;
        List<String> result = justifyText(words, maxWidth);
        for (String line : result) {
            System.out.println(line);
        }
    }
}
