    int intensity;
};

PeakInterval findMaxSubarray(const std::vector<int>& readings) {
    if (readings.empty()) {
        return {-1, -1, 0};
    }

    int max_so_far = INT_MIN;
    int max_ending_here = 0;
    int start = 0;
    int end = 0;
    int temp_start = 0;

    for (int i = 0; i < readings.size(); ++i) {
        max_ending_here += readings[i];

        if (max_so_far < max_ending_here) {
            max_so_far = max_ending_here;
            start = temp_start;
            end = i;
        }

        if (max_ending_here < 0) {
            max_ending_here = 0;
            temp_start = i + 1;
        }
    }

    return {start, end, max_so_far};
}

// Real-time streaming version (processes one reading at a time)
class RealTimePeakDetector {
private:
    int max_so_far;
    int max_ending_here;
    int start;
    int end;
    int temp_start;
    int current_index;

public:
    RealTimePeakDetector() : max_so_far(INT_MIN), max_ending_here(0), 
                            start(0), end(0), temp_start(0), current_index(0) {}

    void processReading(int reading) {
        max_ending_here += reading;

        if (max_so_far < max_ending_here) {
            max_so_far = max_ending_here;
            start = temp_start;
            end = current_index;
        }

        if (max_ending_here < 0) {
            max_ending_here = 0;
            temp_start = current_index + 1;
        }

        current_index++;
    }

    PeakInterval getCurrentPeak() const {
        if (max_so_far == INT_MIN) {
            return {-1, -1, 0};
        }
        return {start, end, max_so_far};
    }
};
