import java.util.*;

public class EvacuationRoutePlanner {
    private int[][] elevationGraph;
    private double[][] flowRates;
    private int nodes;
    private double[][] dp;
    private int[][] nextNode;

    public EvacuationRoutePlanner(int[][] elevationGraph, double[][] flowRates) {
        this.elevationGraph = elevationGraph;
        this.flowRates = flowRates;
        this.nodes = elevationGraph.length;
        this.dp = new double[nodes][nodes];
        this.nextNode = new int[nodes][nodes];
    }

    public void computeSafestPaths() {
        // Initialize DP table and nextNode table
        for (int i = 0; i < nodes; i++) {
            Arrays.fill(dp[i], Double.POSITIVE_INFINITY);
            Arrays.fill(nextNode[i], -1);
            dp[i][i] = 0;
        }

        // Initialize with direct edges
        for (int i = 0; i < nodes; i++) {
            for (int j = 0; j < nodes; j++) {
                if (elevationGraph[i][j] != 0) {
                    dp[i][j] = flowRates[i][j];
                    nextNode[i][j] = j;
                }
            }
        }

        // Dynamic programming to compute safest paths
        for (int k = 0; k < nodes; k++) {
            for (int i = 0; i < nodes; i++) {
                for (int j = 0; j < nodes; j++) {
                    if (dp[i][k] + dp[k][j] < dp[i][j]) {
                        dp[i][j] = dp[i][k] + dp[k][j];
                        nextNode[i][j] = nextNode[i][k];
                    }
                }
            }
        }
    }

    public List<Integer> reconstructPath(int start, int end) {
        if (nextNode[start][end] == -1) {
            return new ArrayList<>(); // No path exists
        }

        List<Integer> path = new ArrayList<>();
        path.add(start);
        while (start != end) {
            start = nextNode[start][end];
            path.add(start);
        }
        return path;
    }

    public void updateFlowRates(double[][] newFlowRates) {
        this.flowRates = newFlowRates;
        computeSafestPaths(); // Recompute paths with updated flow rates
    }
}
