def maximize_profit(projects, budget):
    n = len(projects)
    # Initialize a DP table where dp[i][j] represents the maximum profit for first i projects with budget j
    dp = [[0] * (budget + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        cost, profit = projects[i-1]
        for j in range(1, budget + 1):
            if cost > j:
                dp[i][j] = dp[i-1][j]
            else:
                dp[i][j] = max(dp[i-1][j], dp[i-1][j - cost] + profit)

    return dp[n][budget]
