import java.util.*;

public class SuffixArraySearch {
    private Map<String, List<String>> suffixToTitles = new HashMap<>();
    private List<String> titles;

    public SuffixArraySearch(List<String> titles) {
        this.titles = titles;
        buildSuffixArray();
    }

    private void buildSuffixArray() {
        for (String title : titles) {
            for (int i = 0; i < title.length(); i++) {
                String suffix = title.substring(i).toLowerCase();
                suffixToTitles.computeIfAbsent(suffix, k -> new ArrayList<>()).add(title);
            }
        }
    }

    public List<String> search(String query) {
        query = query.toLowerCase();
        Map<String, Integer> relevanceMap = new HashMap<>();

        for (String suffix : suffixToTitles.keySet()) {
            if (suffix.startsWith(query)) {
                for (String title : suffixToTitles.get(suffix)) {
                    relevanceMap.put(title, relevanceMap.getOrDefault(title, 0) + 1);
                }
            }
        }

        List<Map.Entry<String, Integer>> entries = new ArrayList<>(relevanceMap.entrySet());
        entries.sort((a, b) -> {
            int relevanceCompare = b.getValue().compareTo(a.getValue());
            if (relevanceCompare != 0) return relevanceCompare;
            return a.getKey().compareTo(b.getKey());
        });

        List<String> result = new ArrayList<>();
        for (Map.Entry<String, Integer> entry : entries) {
            result.add(entry.getKey());
        }
        return result;
    }

    public static void main(String[] args) {
        List<String> titles = Arrays.asList(
            "Java Programming",
            "Advanced Java Techniques",
            "Data Structures in Java",
            "Python for Beginners",
            "Java Cookbook"
        );

        SuffixArraySearch searcher = new SuffixArraySearch(titles);
        List<String> results = searcher.search("java");
        System.out.println(results);
    }
}
