import pickle
import os
from collections import deque

class BTreeNode:
    def __init__(self, leaf=False):
        self.leaf = leaf
        self.keys = []
        self.children = []
        self.values = []  # Stores metadata (filename, creation date, size, etc.)

class BTree:
    def __init__(self, t, persistence_file='btree_index.pkl'):
        self.root = BTreeNode(leaf=True)
        self.t = t  # Minimum degree
        self.persistence_file = persistence_file
        self._load_from_disk()

    def _load_from_disk(self):
        if os.path.exists(self.persistence_file):
            with open(self.persistence_file, 'rb') as f:
                data = pickle.load(f)
                self.root = data['root']
                self.t = data['t']

    def _persist_to_disk(self):
        with open(self.persistence_file, 'wb') as f:
            pickle.dump({'root': self.root, 't': self.t}, f)

    def insert(self, key, value):
        root = self.root
        if len(root.keys) == (2 * self.t) - 1:
            new_root = BTreeNode()
            new_root.children.append(self.root)
            self._split_child(new_root, 0)
            self.root = new_root
            self._insert_non_full(new_root, key, value)
        else:
            self._insert_non_full(root, key, value)
        self._persist_to_disk()

    def _insert_non_full(self, node, key, value):
        i = len(node.keys) - 1
        if node.leaf:
            node.keys.append(None)
            node.values.append(None)
            while i >= 0 and key < node.keys[i]:
                node.keys[i + 1] = node.keys[i]
                node.values[i + 1] = node.values[i]
                i -= 1
            node.keys[i + 1] = key
            node.values[i + 1] = value
        else:
            while i >= 0 and key < node.keys[i]:
                i -= 1
            i += 1
            if len(node.children[i].keys) == (2 * self.t) - 1:
                self._split_child(node, i)
                if key > node.keys[i]:
                    i += 1
            self._insert_non_full(node.children[i], key, value)

    def _split_child(self, parent, index):
        t = self.t
        child = parent.children[index]
        new_node = BTreeNode(leaf=child.leaf)
        parent.keys.insert(index, child.keys[t - 1])
        parent.values.insert(index, child.values[t - 1])
        parent.children.insert(index + 1, new_node)
        new_node.keys = child.keys[t:(2 * t) - 1]
        new_node.values = child.values[t:(2 * t) - 1]
        child.keys = child.keys[0:t - 1]
        child.values = child.values[0:t - 1]
        if not child.leaf:
            new_node.children = child.children[t:2 * t]
            child.children = child.children[0:t]

    def search(self, key, node=None):
        if node is None:
            node = self.root
        i = 0
        while i < len(node.keys) and key > node.keys[i]:
            i += 1
        if i < len(node.keys) and key == node.keys[i]:
            return node.values[i]
        elif node.leaf:
            return None
        else:
            return self.search(key, node.children[i])

    def delete(self, key):
        self._delete(self.root, key)
        if len(self.root.keys) == 0 and not self.root.leaf:
            self.root = self.root.children[0]
        self._persist_to_disk()

    def _delete(self, node, key):
        idx = 0
        while idx < len(node.keys) and key > node.keys[idx]:
            idx += 1
        if idx < len(node.keys) and node.keys[idx] == key:
            if node.leaf:
                node.keys.pop(idx)
                node.values.pop(idx)
            else:
                self._delete_internal(node, key, idx)
        else:
            if node.leaf:
                return
            flag = (idx == len(node.keys))
            if len(node.children[idx].keys) < self.t:
                self._fill(node, idx)
            if flag and idx > len(node.keys):
                self._delete(node.children[idx - 1], key)
            else:
                self._delete(node.children[idx], key)

    def _delete_internal(self, node, key, idx):
        if len(node.children[idx].keys) >= self.t:
            predecessor = self._get_predecessor(node, idx)
            node.keys[idx] = predecessor.keys[-1]
            node.values[idx] = predecessor.values[-1]
            self._delete(predecessor, predecessor.keys[-1])
        elif len(node.children[idx + 1].keys) >= self.t:
            successor = self._get_successor(node, idx)
            node.keys[idx] = successor.keys[0]
            node.values[idx] = successor.values[0]
            self._delete(successor, successor.keys[0])
        else:
            self._merge(node, idx)
            self._delete(node.children[idx], key)

    def _get_predecessor(self, node, idx):
        current = node.children[idx]
        while not current.leaf:
            current = current.children[-1]
        return current

    def _get_successor(self, node, idx):
        current = node.children[idx + 1]
        while not current.leaf:
            current = current.children[0]
        return current

    def _fill(self, node, idx):
        if idx != 0 and len(node.children[idx - 1].keys) >= self.t:
            self._borrow_from_prev(node, idx)
        elif idx != len(node.children) - 1 and len(node.children[idx + 1].keys) >= self.t:
            self._borrow_from_next(node, idx)
        else:
            if idx != len(node.children) - 1:
                self._merge(node, idx)
            else:
                self._merge(node, idx - 1)

    def _borrow_from_prev(self, node, idx):
        child = node.children[idx]
        sibling = node.children[idx - 1]
        child.keys.insert(0, node.keys[idx - 1])
        child.values.insert(0, node.values[idx - 1])
        if not child.leaf:
            child.children.insert(0, sibling.children.pop())
        node.keys[idx - 1] = sibling.keys.pop()
        node.values[idx - 1] = sibling.values.pop()

    def _borrow_from_next(self, node, idx):
        child = node.children[idx]
        sibling = node.children[idx + 1]
        child.keys.append(node.keys[idx])
        child.values.append(node.values[idx])
        if not child.leaf:
            child.children.append(sibling.children.pop(0))
        node.keys[idx] = sibling.keys.pop(0)
        node.values[idx] = sibling.values.pop(0)

    def _merge(self, node, idx):
        child = node.children[idx]
        sibling = node.children[idx + 1]
        child.keys.append(node.keys[idx])
        child.values.append(node.values[idx])
        child.keys += sibling.keys
        child.values += sibling.values
        if not child.leaf:
            child.children += sibling.children
        node.keys.pop(idx)
        node.values.pop(idx)
        node.children.pop(idx + 1)

    def traverse(self):
        queue = deque([self.root])
        while queue:
            node = queue.popleft()
            for i, key in enumerate(node.keys):
                if not node.leaf:
                    queue.append(node.children[i])
                print(f"Key: {key}, Value: {node.values[i]}")
            if not node.leaf:
                queue.append(node.children[-1])
