#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

struct Task {
    int priority;
    int executionTime;
    string description;

    Task(int p, int et, string desc) : priority(p), executionTime(et), description(desc) {}
};

class TaskScheduler {
private:
    vector<Task> heap;

    void heapifyUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (heap[parent].priority < heap[index].priority) {
                swap(heap[parent], heap[index]);
                index = parent;
            } else {
                break;
            }
        }
    }

    void heapifyDown(int index) {
        int left, right, largest;
        while (true) {
            left = 2 * index + 1;
            right = 2 * index + 2;
            largest = index;

            if (left < heap.size() && heap[left].priority > heap[largest].priority) {
                largest = left;
            }
            if (right < heap.size() && heap[right].priority > heap[largest].priority) {
                largest = right;
            }

            if (largest != index) {
                swap(heap[index], heap[largest]);
                index = largest;
            } else {
                break;
            }
        }
    }

public:
    void addTask(int priority, int executionTime, string description) {
        heap.emplace_back(priority, executionTime, description);
        heapifyUp(heap.size() - 1);
    }

    Task getNextTask() {
        if (heap.empty()) {
            throw runtime_error("No tasks available");
        }
        return heap.front();
    }

    void removeCompletedTask() {
        if (heap.empty()) {
            throw runtime_error("No tasks available");
        }
        heap[0] = heap.back();
        heap.pop_back();
        heapifyDown(0);
    }

    bool isEmpty() const {
        return heap.empty();
    }
};

int main() {
    TaskScheduler scheduler;
    scheduler.addTask(3, 5, "High priority task");
    scheduler.addTask(1, 2, "Low priority task");
    scheduler.addTask(5, 1, "Critical task");

    while (!scheduler.isEmpty()) {
        Task nextTask = scheduler.getNextTask();
        cout << "Executing: " << nextTask.description 
             << " (Priority: " << nextTask.priority 
             << ", Time: " << nextTask.executionTime << ")" << endl;
        scheduler.removeCompletedTask();
    }

    return 0;
}
