#include <string.h>
#include <stdbool.h>

#define MAX_SERVERS 100

typedef struct {
    int adjacency[MAX_SERVERS][MAX_SERVERS];
    int server_count;
} Graph;

void init_graph(Graph *g) {
    g->server_count = 0;
    for (int i = 0; i < MAX_SERVERS; i++) {
        for (int j = 0; j < MAX_SERVERS; j++) {
            g->adjacency[i][j] = 0;
        }
    }
}

void add_edge(Graph *g, int src, int dest) {
    g->adjacency[src][dest] = 1;
    g->adjacency[dest][src] = 1;
}

bool bfs(Graph *g, int start, int target) {
    bool visited[MAX_SERVERS] = {false};
    int queue[MAX_SERVERS];
    int front = 0, rear = 0;

    queue[rear++] = start;
    visited[start] = true;

    while (front < rear) {
        int current = queue[front++];
        if (current == target) {
            return true;
        }
        for (int i = 0; i < g->server_count; i++) {
            if (g->adjacency[current][i] && !visited[i]) {
                queue[rear++] = i;
                visited[i] = true;
            }
        }
    }
    return false;
}

int main() {
    Graph g;
    init_graph(&g);

    FILE *file = fopen("network.txt", "r");
    if (!file) {
        printf("Error opening file.\n");
        return 1;
    }

    int src, dest;
    while (fscanf(file, "%d %d", &src, &dest) == 2) {
        if (src >= MAX_SERVERS || dest >= MAX_SERVERS) {
            printf("Server ID exceeds maximum limit.\n");
            return 1;
        }
        add_edge(&g, src, dest);
        if (src >= g.server_count) g.server_count = src + 1;
        if (dest >= g.server_count) g.server_count = dest + 1;
    }
    fclose(file);

    int start, target;
    printf("Enter starting server ID: ");
    scanf("%d", &start);
    printf("Enter target server ID: ");
    scanf("%d", &target);

    if (start >= g.server_count || target >= g.server_count) {
        printf("Invalid server ID.\n");
        return 1;
    }

    if (bfs(&g, start, target)) {
        printf("Path exists between server %d and server %d.\n", start, target);
    } else {
        printf("No path exists between server %d and server %d.\n", start, target);
    }

    return 0;
}
