#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_CHAR 256

typedef struct SuffixTreeNode {
    struct SuffixTreeNode *children[MAX_CHAR];
    struct SuffixTreeNode *suffixLink;
    int start;
    int *end;
    int suffixIndex;
} SuffixTreeNode;

typedef struct SuffixTree {
    SuffixTreeNode *root;
    SuffixTreeNode *lastNewNode;
    SuffixTreeNode *activeNode;
    int activeEdge;
    int activeLength;
    int remainingSuffixCount;
    int leafEnd;
    int *rootEnd;
    int *splitEnd;
    int size;
    char *text;
} SuffixTree;

SuffixTreeNode *newNode(int start, int *end) {
    SuffixTreeNode *node = (SuffixTreeNode *)malloc(sizeof(SuffixTreeNode));
    for (int i = 0; i < MAX_CHAR; i++)
        node->children[i] = NULL;
    node->suffixLink = NULL;
    node->start = start;
    node->end = end;
    node->suffixIndex = -1;
    return node;
}

SuffixTree *createSuffixTree(char *text, int n) {
    SuffixTree *st = (SuffixTree *)malloc(sizeof(SuffixTree));
    st->text = text;
    st->size = n;
    st->rootEnd = (int *)malloc(sizeof(int));
    *st->rootEnd = -1;
    st->root = newNode(-1, st->rootEnd);
    st->activeNode = st->root;
    st->activeEdge = -1;
    st->activeLength = 0;
    st->remainingSuffixCount = 0;
    st->leafEnd = -1;
    return st;
}

int edgeLength(SuffixTreeNode *n, SuffixTree *st) {
    return *(n->end) - n->start + 1;
}

int walkDown(SuffixTreeNode *currNode, SuffixTree *st) {
    if (st->activeLength >= edgeLength(currNode, st)) {
        st->activeEdge += edgeLength(currNode, st);
        st->activeLength -= edgeLength(currNode, st);
        st->activeNode = currNode;
        return 1;
    }
    return 0;
}

void extendSuffixTree(SuffixTree *st, int pos) {
    st->leafEnd = pos;
    st->remainingSuffixCount++;
    st->lastNewNode = NULL;

    while (st->remainingSuffixCount > 0) {
        if (st->activeLength == 0)
            st->activeEdge = pos;

        if (st->activeNode->children[st->text[st->activeEdge]] == NULL) {
            st->activeNode->children[st->text[st->activeEdge]] = newNode(pos, &st->leafEnd);
            if (st->lastNewNode != NULL) {
                st->lastNewNode->suffixLink = st->activeNode;
                st->lastNewNode = NULL;
            }
        } else {
            SuffixTreeNode *next = st->activeNode->children[st->text[st->activeEdge]];
            if (walkDown(next, st))
                continue;
            if (st->text[next->start + st->activeLength] == st->text[pos]) {
                if (st->lastNewNode != NULL && st->activeNode != st->root) {
                    st->lastNewNode->suffixLink = st->activeNode;
                    st->lastNewNode = NULL;
                }
                st->activeLength++;
                break;
            }
            st->splitEnd = (int *)malloc(sizeof(int));
            *st->splitEnd = next->start + st->activeLength - 1;
            SuffixTreeNode *split = newNode(next->start, st->splitEnd);
            st->activeNode->children[st->text[st->activeEdge]] = split;
            split->children[st->text[pos]] = newNode(pos, &st->leafEnd);
            next->start += st->activeLength;
            split->children[st->text[next->start]] = next;
            if (st->lastNewNode != NULL) {
                st->lastNewNode->suffixLink = split;
            }
            st->lastNewNode = split;
        }
        st->remainingSuffixCount--;
        if (st->activeNode == st->root && st->activeLength > 0) {
            st->activeLength--;
            st->activeEdge = pos - st->remainingSuffixCount + 1;
        } else if (st->activeNode != st->root) {
            st->activeNode = st->activeNode->suffixLink;
        }
    }
}

void setSuffixIndexByDFS(SuffixTreeNode *n, int labelHeight, SuffixTree *st) {
    if (n == NULL)
        return;
    int leaf = 1;
    for (int i = 0; i < MAX_CHAR; i++) {
        if (n->children[i] != NULL) {
            leaf = 0;
            setSuffixIndexByDFS(n->children[i], labelHeight + edgeLength(n->children[i], st), st);
        }
    }
    if (leaf == 1) {
        n->suffixIndex = st->size - labelHeight;
    }
}

void buildSuffixTree(SuffixTree *st) {
    for (int i = 0; i < st->size; i++)
        extendSuffixTree(st, i);
    setSuffixIndexByDFS(st->root, 0, st);
}

int traverseEdge(char *str, int idx, int start, int end, char *text) {
    for (int k = start; k <= end && str[idx] != '\0'; k++, idx++) {
        if (text[k] != str[idx])
            return -1;
    }
    if (str[idx] == '\0')
        return 1;
    return 0;
}

int doTraversal(SuffixTreeNode *n, char *str, int idx, SuffixTree *st) {
    if (n == NULL)
        return -1;
    if (n->start != -1) {
        int res = traverseEdge(str, idx, n->start, *(n->end), st->text);
        if (res != 0)
            return res;
        idx += edgeLength(n, st);
    }
    if (n->children[str[idx]] == NULL)
        return -1;
    return doTraversal(n->children[str[idx]], str, idx, st);
}

void searchSubstring(SuffixTree *st, char *pattern) {
    int res = doTraversal(st->root, pattern, 0, st);
    if (res == 1)
        printf("Pattern found\n");
    else
        printf("Pattern not found\n");
}

void freeSuffixTreeNodes(SuffixTreeNode *n) {
    if (n == NULL)
        return;
    for (int i = 0; i < MAX_CHAR; i++) {
        if (n->children[i] != NULL) {
            freeSuffixTreeNodes(n->children[i]);
        }
    }
    if (n->suffixIndex == -1)
        free(n->end);
    free(n);
}

void freeSuffixTree(SuffixTree *st) {
    freeSuffixTreeNodes(st->root);
    free(st->rootEnd);
    free(st);
}

int main() {
    char text[100];
    printf("Enter the text: ");
    scanf("%s", text);
    int n = strlen(text);
    SuffixTree *st = createSuffixTree(text, n);
    buildSuffixTree(st);

    int m;
    printf("Enter the number of substrings to search: ");
    scanf("%d", &m);
    while (m--) {
        char pattern[100];
        printf("Enter the substring to search: ");
        scanf("%s", pattern);
        searchSubstring(st, pattern);
    }

    freeSuffixTree(st);
    return 0;
}
