    for (let i = 0; i < n - 1; i++) {
        for (let j = 0; j < n - i - 1; j++) {
            if (sortedGrades[j] > sortedGrades[j + 1]) {
                [sortedGrades[j], sortedGrades[j + 1]] = [sortedGrades[j + 1], sortedGrades[j]];
