use std::collections::HashSet;

fn is_safe(board: &[usize], row: usize, col: usize) -> bool {
    for (r, &c) in board.iter().enumerate() {
        if c == col || r + c == row + col || r as isize - c as isize == row as isize - col as isize {
            return false;
        }
    }
    true
}

fn solve_queens(board: &mut Vec<usize>, row: usize, solutions: &mut Vec<Vec<usize>>) {
    if row == 8 {
        solutions.push(board.clone());
        return;
    }

    for col in 0..8 {
        if is_safe(board, row, col) {
            board.push(col);
            solve_queens(board, row + 1, solutions);
            board.pop();
        }
    }
}

