#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

struct Task {
    string name;
    int duration; // in minutes
    int priority;
};

vector<Task> scheduleTasks(const vector<Task>& tasks, int timeLimit) {
    int n = tasks.size();
    vector<vector<int>> dp(n + 1, vector<int>(timeLimit + 1, 0));

    for (int i = 1; i <= n; ++i) {
        for (int j = 0; j <= timeLimit; ++j) {
            if (tasks[i-1].duration <= j) {
                dp[i][j] = max(dp[i-1][j], dp[i-1][j - tasks[i-1].duration] + tasks[i-1].priority);
            } else {
                dp[i][j] = dp[i-1][j];
            }
        }
    }

    vector<Task> selectedTasks;
    int remainingTime = timeLimit;
    for (int i = n; i > 0 && remainingTime > 0; --i) {
        if (dp[i][remainingTime] != dp[i-1][remainingTime]) {
            selectedTasks.push_back(tasks[i-1]);
            remainingTime -= tasks[i-1].duration;
        }
    }

    return selectedTasks;
}

int main() {
    vector<Task> tasks = {
        {"Task1", 60, 5},
        {"Task2", 120, 8},
        {"Task3", 90, 6},
        {"Task4", 30, 2},
        {"Task5", 180, 10}
    };

    int timeLimit = 480; // 8 hours in minutes
    vector<Task> scheduled = scheduleTasks(tasks, timeLimit);

    cout << "Optimized Schedule (Max Priority within 8 hours):" << endl;
    int totalPriority = 0;
    int totalDuration = 0;
    for (const Task& task : scheduled) {
        cout << task.name << " - Duration: " << task.duration << " mins, Priority: " << task.priority << endl;
        totalPriority += task.priority;
        totalDuration += task.duration;
    }
    cout << "Total Priority: " << totalPriority << endl;
    cout << "Total Duration: " << totalDuration << " mins" << endl;

    return 0;
}
