use std::collections::{BinaryHeap, HashMap, HashSet};
use std::cmp::Ordering;

#[derive(Debug, Clone, Eq, PartialEq)]
struct Edge {
    node: usize,
    weight: usize,
}

impl Ord for Edge {
    fn cmp(&self, other: &Self) -> Ordering {
        other.weight.cmp(&self.weight)
    }
}

impl PartialOrd for Edge {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn prim_mst(edges: &[(usize, usize, usize)], num_nodes: usize) -> Vec<(usize, usize, usize)> {
    let mut adjacency_list: HashMap<usize, Vec<Edge>> = HashMap::new();
    for &(u, v, weight) in edges {
        adjacency_list.entry(u).or_default().push(Edge { node: v, weight });
        adjacency_list.entry(v).or_default().push(Edge { node: u, weight });
    }

    let mut min_heap = BinaryHeap::new();
    let mut visited = HashSet::new();
    let mut mst = Vec::new();

    // Start with node 0
    visited.insert(0);
    for edge in adjacency_list.get(&0).unwrap_or(&vec![]) {
        min_heap.push(edge.clone());
    }

    while visited.len() < num_nodes && !min_heap.is_empty() {
        let edge = min_heap.pop().unwrap();
        if visited.contains(&edge.node) {
            continue;
        }

        let current_node = edge.node;
        visited.insert(current_node);
        mst.push((0, current_node, edge.weight)); // Replace 0 with actual parent if tracking

        for neighbor in adjacency_list.get(&current_node).unwrap_or(&vec![]) {
            if !visited.contains(&neighbor.node) {
                min_heap.push(neighbor.clone());
            }
        }
    }

    mst
}

fn main() {
    let edges = vec![
        (0, 1, 4),
        (0, 7, 8),
        (1, 2, 8),
        (1, 7, 11),
        (2, 3, 7),
        (2, 8, 2),
        (2, 5, 4),
        (3, 4, 9),
        (3, 5, 14),
        (4, 5, 10),
        (5, 6, 2),
        (6, 7, 1),
        (6, 8, 6),
        (7, 8, 7),
    ];
    let num_nodes = 9;
    let mst = prim_mst(&edges, num_nodes);
    println!("Minimum Spanning Tree Edges: {:?}", mst);
}
