class BloomFilter {
  constructor(size, hashCount) {
    this.size = size;
    this.hashCount = hashCount;
    this.bitArray = new Array(size).fill(false);
  }

  add(item) {
    for (let i = 0; i < this.hashCount; i++) {
      const hash = this._getHash(item, i);
      this.bitArray[hash % this.size] = true;
    }
  }

  check(item) {
    for (let i = 0; i < this.hashCount; i++) {
      const hash = this._getHash(item, i);
      if (!this.bitArray[hash % this.size]) {
        return false;
      }
    }
    return true;
  }

  _getHash(item, seed) {
    let hash = 0;
    for (let i = 0; i < item.length; i++) {
      hash = (hash << 5) + hash + item.charCodeAt(i) + seed;
      hash = hash & hash; // Convert to 32bit integer
      hash = Math.abs(hash);
    }
    return hash;
  }

  visualize() {
    console.log("Bloom Filter State:");
    console.log(this.bitArray.map(bit => bit ? '1' : '0').join(' '));
  }
}

// Example usage:
const bloomFilter = new BloomFilter(20, 3);
console.log("Initial state:");
bloomFilter.visualize();

