import java.util.ArrayList;
import java.util.List;
import java.util.Random;

public class UniversalHashTable<K, V> {
    private static class Entry<K, V> {
        K key;
        V value;
        Entry<K, V> next;

        Entry(K key, V value) {
            this.key = key;
            this.value = value;
        }
    }

    private List<Entry<K, V>>[] table;
    private int size;
    private int capacity;
    private final double maxLoadFactor = 0.75;
    private int a, b, p;

    public UniversalHashTable(int initialCapacity) {
        this.capacity = initialCapacity;
        this.table = new ArrayList[capacity];
        for (int i = 0; i < capacity; i++) {
            table[i] = new ArrayList<>();
        }
        Random rand = new Random();
        this.p = getNextPrime(capacity);
        this.a = rand.nextInt(p - 1) + 1;
        this.b = rand.nextInt(p);
    }

    private int getNextPrime(int num) {
        while (!isPrime(num)) {
            num++;
        }
        return num;
    }

    private boolean isPrime(int num) {
        if (num <= 1) return false;
        if (num == 2) return true;
        if (num % 2 == 0) return false;
        for (int i = 3; i * i <= num; i += 2) {
            if (num % i == 0) return false;
        }
        return true;
    }

    private int universalHash(K key) {
        int hash = key.hashCode();
        return ((a * hash + b) % p) % capacity;
    }

    public void put(K key, V value) {
        if ((double) size / capacity >= maxLoadFactor) {
            resize();
        }
        int index = universalHash(key);
        for (Entry<K, V> entry : table[index]) {
            if (entry.key.equals(key)) {
                entry.value = value;
                return;
            }
        }
        table[index].add(new Entry<>(key, value));
        size++;
    }

    public V get(K key) {
        int index = universalHash(key);
        for (Entry<K, V> entry : table[index]) {
            if (entry.key.equals(key)) {
                return entry.value;
            }
        }
        return null;
    }

    public void remove(K key) {
        int index = universalHash(key);
        Entry<K, V> toRemove = null;
        for (Entry<K, V> entry : table[index]) {
            if (entry.key.equals(key)) {
                toRemove = entry;
                break;
            }
        }
        if (toRemove != null) {
            table[index].remove(toRemove);
            size--;
        }
    }

    private void resize() {
        int newCapacity = capacity * 2;
        List<Entry<K, V>>[] newTable = new ArrayList[newCapacity];
        for (int i = 0; i < newCapacity; i++) {
            newTable[i] = new ArrayList<>();
        }
        p = getNextPrime(newCapacity);
        Random rand = new Random();
        a = rand.nextInt(p - 1) + 1;
        b = rand.nextInt(p);
        for (List<Entry<K, V>> bucket : table) {
            for (Entry<K, V> entry : bucket) {
                int newIndex = ((a * entry.key.hashCode() + b) % p) % newCapacity;
                newTable[newIndex].add(entry);
            }
        }
        table = newTable;
        capacity = newCapacity;
    }

    public void printStats() {
        System.out.println("Hash Table Statistics:");
        System.out.println("Size: " + size);
        System.out.println("Capacity: " + capacity);
        System.out.println("Load Factor: " + (double) size / capacity);
        System.out.println("Universal Hash Parameters: a=" + a + ", b=" + b + ", p=" + p);
        int maxChainLength = 0;
        int emptyBuckets = 0;
        for (List<Entry<K, V>> bucket : table) {
            if (bucket.isEmpty()) {
                emptyBuckets++;
            } else if (bucket.size() > maxChainLength) {
                maxChainLength = bucket.size();
            }
        }
        System.out.println("Max Chain Length: " + maxChainLength);
        System.out.println("Empty Buckets: " + emptyBuckets);
    }
}
