fn max_tasks(tasks: &[Task], max_requirements: usize) -> Vec<u32> {
    let mut selected_tasks = Vec::new();
    let mut used_requirements = HashSet::new();
    let mut remaining_tasks = tasks.to_vec();

    // Sort tasks by number of requirements (descending) to prioritize those with most dependencies
    remaining_tasks.sort_by(|a, b| b.requirements.len().cmp(&a.requirements.len()));

    for task in remaining_tasks {
        let new_requirements: HashSet<_> = task.requirements.difference(&used_requirements).collect();
        if used_requirements.len() + new_requirements.len() <= max_requirements {
            used_requirements.extend(task.requirements.iter().cloned());
            selected_tasks.push(task.id);
        }
    }

    selected_tasks
}

