import java.util.ArrayList;
import java.util.List;
import java.util.Random;

class SkipListNode {
    int value;
    List<SkipListNode> forward;

    public SkipListNode(int value, int level) {
        this.value = value;
        this.forward = new ArrayList<>(level);
        for (int i = 0; i < level; i++) {
            forward.add(null);
        }
    }
}

public class SkipList {
    private static final int MAX_LEVEL = 16;
    private int level;
    private SkipListNode header;
    private Random random;

    public SkipList() {
        this.level = 1;
        this.header = new SkipListNode(Integer.MIN_VALUE, MAX_LEVEL);
        this.random = new Random();
    }

    private int randomLevel() {
        int lvl = 1;
        while (lvl < MAX_LEVEL && random.nextDouble() < 0.5) {
            lvl++;
        }
        return lvl;
    }

    public boolean search(int target) {
        SkipListNode current = header;
        for (int i = level - 1; i >= 0; i--) {
            while (current.forward.get(i) != null && current.forward.get(i).value < target) {
                current = current.forward.get(i);
            }
        }
        current = current.forward.get(0);
        return current != null && current.value == target;
    }

    public void insert(int value) {
        List<SkipListNode> update = new ArrayList<>(MAX_LEVEL);
        for (int i = 0; i < MAX_LEVEL; i++) {
            update.add(null);
        }
        SkipListNode current = header;
        for (int i = level - 1; i >= 0; i--) {
            while (current.forward.get(i) != null && current.forward.get(i).value < value) {
                current = current.forward.get(i);
            }
            update.set(i, current);
        }
        current = current.forward.get(0);
        if (current == null || current.value != value) {
            int newLevel = randomLevel();
            if (newLevel > level) {
                for (int i = level; i < newLevel; i++) {
                    update.set(i, header);
                }
                level = newLevel;
            }
            SkipListNode newNode = new SkipListNode(value, newLevel);
            for (int i = 0; i < newLevel; i++) {
                newNode.forward.set(i, update.get(i).forward.get(i));
                update.get(i).forward.set(i, newNode);
            }
        }
        visualize();
    }

    public void delete(int value) {
        List<SkipListNode> update = new ArrayList<>(MAX_LEVEL);
        for (int i = 0; i < MAX_LEVEL; i++) {
            update.add(null);
        }
        SkipListNode current = header;
        for (int i = level - 1; i >= 0; i--) {
            while (current.forward.get(i) != null && current.forward.get(i).value < value) {
                current = current.forward.get(i);
            }
            update.set(i, current);
        }
        current = current.forward.get(0);
        if (current != null && current.value == value) {
            for (int i = 0; i < level; i++) {
                if (update.get(i).forward.get(i) != current) {
                    break;
                }
                update.get(i).forward.set(i, current.forward.get(i));
            }
            while (level > 1 && header.forward.get(level - 1) == null) {
                level--;
            }
        }
        visualize();
    }

    public void visualize() {
        System.out.println("Skip List Structure (Levels: " + level + "):");
        for (int i = level - 1; i >= 0; i--) {
            System.out.print("Level " + i + ": ");
            SkipListNode node = header.forward.get(i);
            while (node != null) {
                System.out.print(node.value + " -> ");
                node = node.forward.get(i);
            }
            System.out.println("null");
        }
        System.out.println();
    }

    public static void main(String[] args) {
        SkipList skipList = new SkipList();
        skipList.insert(3);
        skipList.insert(6);
        skipList.insert(7);
        skipList.insert(9);
        skipList.insert(12);
        skipList.insert(19);
        skipList.insert(17);
        skipList.insert(26);
        skipList.insert(21);
        skipList.insert(25);
        skipList.delete(19);
        skipList.delete(21);
    }
}
