class TreeNode {
    constructor(val) {
        this.val = val;
        this.left = null;
        this.right = null;
    }
}

class BinaryTreeLCA {
    constructor(root) {
        this.root = root;
        this.up = [];
        this.depth = [];
        this.log = 0;
        this.nodes = new Map();
        this.nodeExists = new Set();
        this.preprocess();
    }

    preprocess() {
        if (!this.root) return;

        const stack = [{ node: this.root, parent: null, level: 0 }];
        const nodeList = [];

        while (stack.length > 0) {
            const { node, parent, level } = stack.pop();
            this.nodes.set(node.val, node);
            this.nodeExists.add(node.val);
            nodeList.push(node);
            this.depth[node.val] = level;

            if (parent === null) {
                this.up[node.val] = Array(this.log).fill(null);
            } else {
                this.up[node.val] = Array(this.log).fill(null);
                this.up[node.val][0] = parent.val;
                for (let j = 1; j < this.log; ++j) {
                    const ancestor = this.up[node.val][j - 1];
                    this.up[node.val][j] = ancestor !== null ? this.up[ancestor][j - 1] : null;
                }
            }

            if (node.right) stack.push({ node: node.right, parent: node, level: level + 1 });
            if (node.left) stack.push({ node: node.left, parent: node, level: level + 1 });
        }

        let maxDepth = 0;
        for (const node of nodeList) {
            maxDepth = Math.max(maxDepth, this.depth[node.val]);
        }

        this.log = Math.floor(Math.log2(maxDepth)) + 1;

        for (const node of nodeList) {
            while (this.up[node.val].length < this.log) {
                const ancestor = this.up[node.val][this.up[node.val].length - 1];
                this.up[node.val].push(ancestor !== null ? this.up[ancestor][this.up[node.val].length - 1] : null);
            }
        }
    }

    findLCA(u, v) {
        if (!this.nodeExists.has(u) || !this.nodeExists.has(v)) return null;

        let a = u;
        let b = v;

        if (this.depth[a] < this.depth[b]) {
            [a, b] = [b, a];
        }

        for (let i = this.log - 1; i >= 0; --i) {
            if (this.depth[a] - (1 << i) >= this.depth[b]) {
                a = this.up[a][i];
            }
        }

        if (a === b) return a;

        for (let i = this.log - 1; i >= 0; --i) {
            if (this.up[a][i] !== null && this.up[a][i] !== this.up[b][i]) {
                a = this.up[a][i];
                b = this.up[b][i];
            }
        }

        return this.up[a][0];
    }
}

function lowestCommonAncestor(root, p, q) {
    const lcaFinder = new BinaryTreeLCA(root);
    const lca = lcaFinder.findLCA(p, q);
    return lca !== null ? lcaFinder.nodes.get(lca) : null;
}
