#include <iostream>
#include <string>
#include <algorithm>
using namespace std;

struct Song {
    string title;
    Song* prev;
    Song* next;
};

class Playlist {
private:
    Song* head;
    Song* tail;
    int count;

public:
    Playlist() : head(nullptr), tail(nullptr), count(0) {}

    ~Playlist() {
        Song* current = head;
        while (current != nullptr) {
            Song* next = current->next;
            delete current;
            current = next;
        }
    }

    bool isFull() {
        return count >= 50;
    }

    void addSong(const string& title) {
        if (isFull()) {
            cout << "Playlist is full (max 50 songs)." << endl;
            return;
        }

        Song* newSong = new Song{title, nullptr, nullptr};
        if (head == nullptr) {
            head = tail = newSong;
        } else {
            tail->next = newSong;
            newSong->prev = tail;
            tail = newSong;
        }
        count++;
    }

    void removeSong(const string& title) {
        Song* current = head;
        while (current != nullptr) {
            if (current->title == title) {
                if (current->prev != nullptr) {
                    current->prev->next = current->next;
                } else {
                    head = current->next;
                }
                if (current->next != nullptr) {
                    current->next->prev = current->prev;
                } else {
                    tail = current->prev;
                }
                delete current;
                count--;
                return;
            }
            current = current->next;
        }
        cout << "Song not found." << endl;
    }

    void displayPlaylist() {
        Song* current = head;
        while (current != nullptr) {
            cout << current->title << endl;
            current = current->next;
        }
    }

    void sortPlaylist() {
        if (head == nullptr) return;

        Song* songs[50];
        Song* current = head;
        int i = 0;
        while (current != nullptr && i < 50) {
            songs[i++] = current;
            current = current->next;
        }

        sort(songs, songs + i, [](Song* a, Song* b) {
            return a->title < b->title;
        });

        head = songs[0];
        head->prev = nullptr;
        for (int j = 1; j < i; j++) {
            songs[j-1]->next = songs[j];
            songs[j]->prev = songs[j-1];
        }
        songs[i-1]->next = nullptr;
        tail = songs[i-1];
    }

    void navigatePlaylist() {
        if (head == nullptr) {
            cout << "Playlist is empty." << endl;
            return;
        }

        Song* current = head;
        char choice;
        do {
            cout << "Current song: " << current->title << endl;
            cout << "Options: [N]ext, [P]revious, [Q]uit: ";
            cin >> choice;
            choice = toupper(choice);

            switch (choice) {
                case 'N':
                    if (current->next != nullptr) {
                        current = current->next;
                    } else {
                        cout << "End of playlist." << endl;
                    }
                    break;
                case 'P':
                    if (current->prev != nullptr) {
                        current = current->prev;
                    } else {
                        cout << "Start of playlist." << endl;
                    }
                    break;
                case 'Q':
                    break;
                default:
                    cout << "Invalid option." << endl;
            }
        } while (choice != 'Q');
    }
};

int main() {
    Playlist playlist;
    int choice;
    string title;

    do {
        cout << "\nPlaylist Menu:\n";
        cout << "1. Add Song\n";
        cout << "2. Remove Song\n";
        cout << "3. Display Playlist\n";
        cout << "4. Sort Playlist\n";
        cout << "5. Navigate Playlist\n";
        cout << "6. Exit\n";
        cout << "Enter choice: ";
        cin >> choice;
        cin.ignore();

        switch (choice) {
            case 1:
                cout << "Enter song title: ";
                getline(cin, title);
                playlist.addSong(title);
                break;
            case 2:
                cout << "Enter song title to remove: ";
                getline(cin, title);
                playlist.removeSong(title);
                break;
            case 3:
                playlist.displayPlaylist();
                break;
            case 4:
                playlist.sortPlaylist();
                cout << "Playlist sorted." << endl;
                break;
            case 5:
                playlist.navigatePlaylist();
                break;
            case 6:
                break;
            default:
                cout << "Invalid choice." << endl;
        }
    } while (choice != 6);

    return 0;
}
