#include <iostream>
#include <stack>
#include <string>
#include <sstream>
#include <stdexcept>
#include <cctype>

using namespace std;

bool isOperator(const string& token) {
    return token == "+" || token == "-" || token == "*" || token == "/";
}

double performOperation(double a, double b, const string& op) {
    if (op == "+") return a + b;
    if (op == "-") return a - b;
    if (op == "*") return a * b;
    if (op == "/") {
        if (b == 0) throw runtime_error("Division by zero");
        return a / b;
    }
    throw runtime_error("Invalid operator");
}

bool isNumber(const string& s) {
    istringstream iss(s);
    double dummy;
    iss >> dummy;
    return iss.eof() && !iss.fail();
}

void validatePostfix(const string& expression) {
    istringstream iss(expression);
    string token;
    int operandCount = 0;

    while (iss >> token) {
        if (isNumber(token)) {
            operandCount++;
        } else if (isOperator(token)) {
            if (operandCount < 2) {
                throw runtime_error("Invalid postfix expression");
            }
            operandCount--;
        } else {
            throw runtime_error("Invalid token in expression");
        }
    }

    if (operandCount != 1) {
        throw runtime_error("Invalid postfix expression");
    }
}

double evaluatePostfix(const string& expression) {
    stack<double> s;
    istringstream iss(expression);
    string token;

    while (iss >> token) {
        if (isNumber(token)) {
            s.push(stod(token));
        } else if (isOperator(token)) {
            if (s.size() < 2) {
                throw runtime_error("Invalid postfix expression");
            }
            double b = s.top(); s.pop();
            double a = s.top(); s.pop();
            s.push(performOperation(a, b, token));
        } else {
            throw runtime_error("Invalid token in expression");
        }
    }

    if (s.size() != 1) {
        throw runtime_error("Invalid postfix expression");
    }

    return s.top();
}

int main() {
    string expression;
    cout << "Enter postfix expression: ";
    getline(cin, expression);

    try {
        validatePostfix(expression);
        double result = evaluatePostfix(expression);
        cout << "Result: " << result << endl;
    } catch (const exception& e) {
        cerr << "Error: " << e.what() << endl;
    }

    return 0;
}
