function selectionSortGrades(grades) {
    if (!Array.isArray(grades) || grades.length === 0) {
        return [];
    }

    const sortedGrades = [...grades];
    const n = sortedGrades.length;

    for (let i = 0; i < n - 1; i++) {
        let minIndex = i;

        for (let j = i + 1; j < n; j++) {
            if (sortedGrades[j] < sortedGrades[minIndex]) {
                minIndex = j;
            }
        }

        if (minIndex !== i) {
            [sortedGrades[i], sortedGrades[minIndex]] = [sortedGrades[minIndex], sortedGrades[i]];
        }
    }

    return sortedGrades;
}
