class FibonacciHeapNode:
    def __init__(self, key):
        self.key = key
        self.degree = 0
        self.parent = None
        self.child = None
        self.left = self
        self.right = self
        self.marked = False

class FibonacciHeap:
    def __init__(self):
        self.min_node = None
        self.num_nodes = 0

    def insert(self, key):
        node = FibonacciHeapNode(key)
        if self.min_node is None:
            self.min_node = node
        else:
            self._add_to_root_list(node)
            if node.key < self.min_node.key:
                self.min_node = node
        self.num_nodes += 1
        return node

    def _add_to_root_list(self, node):
        node.left = self.min_node
        node.right = self.min_node.right
        self.min_node.right.left = node
        self.min_node.right = node

    def extract_min(self):
        z = self.min_node
        if z is not None:
            if z.child is not None:
                children = [x for x in self._iterate_nodes(z.child)]
                for x in children:
                    self._add_to_root_list(x)
                    x.parent = None
            self._remove_from_root_list(z)
            if z == z.right:
                self.min_node = None
            else:
                self.min_node = z.right
                self._consolidate()
            self.num_nodes -= 1
        return z

    def _consolidate(self):
        max_degree = int(self._log2(self.num_nodes)) + 1
        degree_array = [None] * (max_degree + 1)
        nodes = [x for x in self._iterate_nodes(self.min_node)]
        for w in nodes:
            x = w
            d = x.degree
            while degree_array[d] is not None:
                y = degree_array[d]
                if x.key > y.key:
                    x, y = y, x
                self._heap_link(y, x)
                degree_array[d] = None
                d += 1
            degree_array[d] = x
        self.min_node = None
        for node in degree_array:
            if node is not None:
                if self.min_node is None:
                    self.min_node = node
                else:
                    if node.key < self.min_node.key:
                        self.min_node = node

    def _heap_link(self, y, x):
        self._remove_from_root_list(y)
        y.left = y.right = y
        self._add_child(x, y)
        x.degree += 1
        y.parent = x
        y.marked = False

    def _add_child(self, parent, child):
        if parent.child is None:
            parent.child = child
        else:
            child.right = parent.child.right
            child.left = parent.child
            parent.child.right.left = child
            parent.child.right = child

    def _remove_from_root_list(self, node):
        node.left.right = node.right
        node.right.left = node.left

    def _iterate_nodes(self, start):
        current = start
        while True:
            yield current
            current = current.right
            if current == start:
                break

    def _log2(self, x):
        return x.bit_length() - 1

    def decrease_key(self, node, new_key):
        if new_key > node.key:
            raise ValueError("New key is greater than current key")
        node.key = new_key
        parent = node.parent
        if parent is not None and node.key < parent.key:
            self._cut(node, parent)
            self._cascading_cut(parent)
        if node.key < self.min_node.key:
            self.min_node = node

    def _cut(self, node, parent):
        self._remove_child(parent, node)
        parent.degree -= 1
        self._add_to_root_list(node)
        node.parent = None
        node.marked = False

    def _remove_child(self, parent, child):
        if parent.child == parent.child.right:
            parent.child = None
        elif parent.child == child:
            parent.child = child.right
            child.right.parent = parent
        child.left.right = child.right
        child.right.left = child.left

    def _cascading_cut(self, node):
        parent = node.parent
        if parent is not None:
            if not node.marked:
                node.marked = True
            else:
                self._cut(node, parent)
                self._cascading_cut(parent)

    def delete(self, node):
        self.decrease_key(node, float('-inf'))
        self.extract_min()

    def merge(self, other_heap):
        if other_heap.min_node is None:
            return
        if self.min_node is None:
            self.min_node = other_heap.min_node
        else:
            self_min_right = self.min_node.right
            other_min_left = other_heap.min_node.left
            self.min_node.right = other_heap.min_node
            other_heap.min_node.left = self.min_node
            self_min_right.left = other_min_left
            other_min_left.right = self_min_right
            if other_heap.min_node.key < self.min_node.key:
                self.min_node = other_heap.min_node
        self.num_nodes += other_heap.num_nodes

# Example usage
if __name__ == "__main__":
    fh1 = FibonacciHeap()
    fh2 = FibonacciHeap()
    fh1.insert(5)
    fh1.insert(3)
    fh1.insert(7)
    fh2.insert(2)
    fh2.insert(6)
    fh1.merge(fh2)
    print(fh1.extract_min().key)  # Output: 2
    print(fh1.extract_min().key)  # Output: 3
    print(fh1.extract_min().key)  # Output: 5
    print(fh1.extract_min().key)  # Output: 6
    print(fh1.extract_min().key)  # Output: 7
