#[derive(Debug)]
struct Graph {
    edges: Vec<(usize, usize, i32)>,
    vertices: usize,
}

impl Graph {
    fn new(vertices: usize) -> Self {
        Graph {
            edges: Vec::new(),
            vertices,
        }
    }

    fn add_edge(&mut self, u: usize, v: usize, weight: i32) {
        self.edges.push((u, v, weight));
    }

    fn bellman_ford(&self, source: usize) -> Option<Vec<i32>> {
        let mut distances = vec![i32::MAX; self.vertices];
        distances[source] = 0;

        for _ in 0..self.vertices - 1 {
            for &(u, v, weight) in &self.edges {
                if distances[u] != i32::MAX && distances[v] > distances[u] + weight {
                    distances[v] = distances[u] + weight;
                }
            }
        }

        for &(u, v, weight) in &self.edges {
            if distances[u] != i32::MAX && distances[v] > distances[u] + weight {
                return None; // Negative weight cycle detected
            }
        }

        Some(distances)
    }
}

fn main() {
    let mut graph = Graph::new(5);
    graph.add_edge(0, 1, -1);
    graph.add_edge(0, 2, 4);
    graph.add_edge(1, 2, 3);
    graph.add_edge(1, 3, 2);
    graph.add_edge(1, 4, 2);
    graph.add_edge(3, 2, 5);
    graph.add_edge(3, 1, 1);
    graph.add_edge(4, 3, -3);

    let source = 0;
    match graph.bellman_ford(source) {
        Some(distances) => {
            println!("Shortest travel times from station {}:", source);
            for (i, &d) in distances.iter().enumerate() {
                println!("To station {}: {}", i, d);
            }
        }
        None => println!("Negative weight cycle detected. Inconsistent route data."),
    }
}
