function mergeSortStudents(students) {
    if (students.length <= 1) {
        return students;
    }

    const mid = Math.floor(students.length / 2);
    const left = mergeSortStudents(students.slice(0, mid));
    const right = mergeSortStudents(students.slice(mid));

    return merge(left, right);
}

function merge(left, right) {
    let result = [];
    let i = 0;
    let j = 0;

    while (i < left.length && j < right.length) {
        if (left[i].score > right[j].score) {
            result.push(left[i]);
            i++;
        } else if (left[i].score < right[j].score) {
            result.push(right[j]);
            j++;
        } else {
            if (left[i].name.localeCompare(right[j].name) < 0) {
                result.push(left[i]);
                i++;
            } else {
                result.push(right[j]);
                j++;
            }
        }
    }

    return result.concat(left.slice(i)).concat(right.slice(j));
}

// Example usage:
