function createFitnessPlan(exercises, dailyMaxDuration = 60) {
    // Calculate calorie burn per minute ratio for each exercise
    const exercisesWithRatio = exercises.map(exercise => ({
        ...exercise,
        ratio: exercise.calories / exercise.duration
    }));

    // Sort exercises by ratio in descending order
    exercisesWithRatio.sort((a, b) => b.ratio - a.ratio);

    const weeklyPlan = {};
    const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];

    days.forEach(day => {
        let remainingTime = dailyMaxDuration;
        weeklyPlan[day] = [];

        for (const exercise of exercisesWithRatio) {
            if (exercise.duration <= remainingTime) {
                weeklyPlan[day].push(exercise);
                remainingTime -= exercise.duration;
            }
            if (remainingTime <= 0) break;
        }
    });

    return weeklyPlan;
}

// Example usage:
const exercises = [
    { name: 'Running', duration: 30, calories: 300 },
    { name: 'Cycling', duration: 45, calories: 400 },
    { name: 'Swimming', duration: 60, calories: 500 },
    { name: 'Jump Rope', duration: 15, calories: 200 },
    { name: 'Weight Lifting', duration: 60, calories: 250 }
];

const fitnessPlan = createFitnessPlan(exercises);
